/**
 * YOU PROBABLY DON'T NEED TO EDIT THIS FILE, UNLESS:
 * 1. You want to modify request context (see Part 1)
 * 2. You want to create a new middleware or type of procedure (see Part 3)
 *
 * tl;dr - this is where all the tRPC server stuff is created and plugged in.
 * The pieces you will need to use are documented accordingly near the end
 */

import { db } from "@db/app/client";
import { getCachedUserOrgMemberships } from "@repo/app-clerk-cache";
import { initTRPC, TRPCError } from "@trpc/server";
import { auth } from "@vendor/clerk/server";
import { createObservabilityMiddleware } from "@vendor/observability/trpc";
import superjson from "superjson";
import { ZodError } from "zod";

/**
 * Authentication Context - Discriminated Union
 * Represents exactly one authentication method per request
 */
type AuthContext =
  | {
      type: "clerk-pending";
      userId: string;
      // Authenticated but hasn't claimed an organization yet
      // Only allowed for onboarding procedures
    }
  | {
      type: "clerk-active";
      userId: string;
      orgId: string;
      // Authenticated and has claimed an organization
      // Can access all org-scoped resources
    }
  | {
      type: "unauthenticated";
    };

/**
 * 1. CONTEXT
 *
 * This section defines the "contexts" that are available in the backend API.
 *
 * These allow you to access things when processing a request, like the database, the session, etc.
 *
 * This helper generates the "internals" for a tRPC context. The API handler and RSC clients each
 * wrap this and provides the required context.
 *
 * @see https://trpc.io/docs/server/context
 */

/**
 * Unified tRPC context factory (Clerk auth only)
 *
 * API key auth is handled by the REST layer (withApiKeyAuth, withDualAuth),
 * not tRPC. The CLI uses REST endpoints, not tRPC procedures.
 */
export const createTRPCContext = async (opts: { headers: Headers }) => {
  const clerkSession = await auth({ treatPendingAsSignedOut: false });

  if (clerkSession.userId) {
    if (clerkSession.orgId) {
      return {
        auth: {
          type: "clerk-active" as const,
          userId: clerkSession.userId,
          orgId: clerkSession.orgId,
        },
        db,
        headers: opts.headers,
      };
    }
    return {
      auth: {
        type: "clerk-pending" as const,
        userId: clerkSession.userId,
      },
      db,
      headers: opts.headers,
    };
  }

  return {
    auth: { type: "unauthenticated" as const },
    db,
    headers: opts.headers,
  };
};

/**
 * 2. INITIALIZATION
 *
 * This is where the trpc api is initialized, connecting the context and
 * transformer
 *
 * Uses the unified createTRPCContext factory (Clerk auth only).
 */
const isProduction = process.env.NODE_ENV === "production";

const t = initTRPC.context<typeof createTRPCContext>().create({
  transformer: superjson,
  errorFormatter: ({ shape, error }) => {
    // In production, sanitize INTERNAL_SERVER_ERROR messages to prevent credential leaks.
    // Procedures that throw TRPCError with specific codes (CONFLICT, BAD_REQUEST, etc.)
    // intentionally set user-facing messages, so those are preserved.
    const shouldSanitize =
      isProduction && error.code === "INTERNAL_SERVER_ERROR";

    return {
      ...shape,
      message: shouldSanitize ? "An unexpected error occurred" : shape.message,
      data: {
        ...shape.data,
        zodError:
          error.cause instanceof ZodError ? error.cause.flatten() : null,
      },
    };
  },
});

/**
 * 3. ROUTER & PROCEDURE (THE IMPORTANT BIT)
 *
 * These are the pieces you use to build your tRPC API. You should import these
 * a lot in the /src/server/api/routers folder
 */

/**
 * This is how you create new routers and subrouters in your tRPC API
 * @see https://trpc.io/docs/router
 */
export const createTRPCRouter = t.router;

/**
 * Create a server-side caller
 * @see https://trpc.io/docs/server/server-side-calls
 */
export const createCallerFactory = t.createCallerFactory;

/**
 * Middleware for timing procedure execution and adding an artificial delay in development.
 *
 * You can remove this if you don't like it, but it can help catch unwanted waterfalls by simulating
 * network latency that would occur in production but not in local development.
 */
const observabilityMiddleware = t.middleware(
  createObservabilityMiddleware({
    isDev: t._config.isDev,
    extractAuth: (ctx) => ({
      ...(ctx.auth.type === "clerk-active" && {
        userId: ctx.auth.userId,
        orgId: ctx.auth.orgId,
      }),
      ...(ctx.auth.type === "clerk-pending" && {
        userId: ctx.auth.userId,
      }),
    }),
  })
);

/**
 * Public (unauthed) procedure
 *
 * This is the base piece you use to build new queries and mutations on your
 * tRPC API. It does not guarantee that a user querying is authorized, but you
 * can still access user session data if they are logged in
 */
export const publicProcedure = t.procedure.use(observabilityMiddleware);

/**
 * User-Scoped Procedure
 *
 * For user-level operations: account settings, profile, list orgs, create org.
 * Accepts both clerk-pending (no org) and clerk-active (has org) users.
 *
 * Use cases:
 * - User profile and settings
 * - List user's organizations
 * - Create new organization
 * - User-level integrations (GitHub account connection)
 *
 * For org-scoped operations (repos, integrations), use `orgScopedProcedure`.
 *
 * @see https://trpc.io/docs/procedures
 */
export const userScopedProcedure = t.procedure
  .use(observabilityMiddleware)
  .use(({ ctx, next }) => {
    if (ctx.auth.type === "unauthenticated") {
      throw new TRPCError({
        code: "UNAUTHORIZED",
        message: "Authentication required. Please sign in.",
      });
    }

    // Allow both clerk-pending and clerk-active
    if (ctx.auth.type !== "clerk-pending" && ctx.auth.type !== "clerk-active") {
      throw new TRPCError({
        code: "UNAUTHORIZED",
        message: "Clerk authentication required",
      });
    }

    return next({
      ctx: {
        ...ctx,
        // Type-safe: either clerk-pending or clerk-active
        auth: ctx.auth as Extract<
          AuthContext,
          { type: "clerk-pending" | "clerk-active" }
        >,
      },
    });
  });

/**
 * Org-Scoped Procedure
 *
 * For org-level operations: repositories, members, integrations.
 * Only accepts clerk-active users (authenticated + has claimed org).
 *
 * Type-safe: `ctx.auth.orgId` is guaranteed to exist.
 *
 * Use cases:
 * - Repositories (connect, sync)
 * - Org members (invite, remove)
 * - Org integrations (GitHub org, Slack)
 * - Org settings
 *
 * For user-level operations (profile, create org), use `userScopedProcedure`.
 *
 * @see https://trpc.io/docs/procedures
 */
export const orgScopedProcedure = t.procedure
  .use(observabilityMiddleware)
  .use(({ ctx, next }) => {
    if (ctx.auth.type === "unauthenticated") {
      throw new TRPCError({
        code: "UNAUTHORIZED",
        message: "Authentication required. Please sign in.",
      });
    }

    // Only allow clerk-active (has org)
    if (ctx.auth.type !== "clerk-active") {
      throw new TRPCError({
        code: "FORBIDDEN",
        message:
          "Organization required. Please create or join an organization first.",
      });
    }

    return next({
      ctx: {
        ...ctx,
        // Type-safe: orgId is guaranteed to exist
        auth: ctx.auth as Extract<AuthContext, { type: "clerk-active" }>,
      },
    });
  });

/**
 * Helper: Verify organization membership
 *
 * Strategy: User-centric lookup with caching - fetches user's orgs (typically 1-5)
 * instead of org's members (could be 100+). This is O(user_orgs) vs O(org_size).
 *
 * This centralizes the pattern of:
 * 1. Fetching user's organization memberships (cached)
 * 2. Verifying user has access to the organization
 * 3. Optionally verifying user has admin role
 * 4. Returning the membership object for further processing
 *
 * Use this in procedures that need to verify organization-level access
 * (organization settings, member management, etc.)
 *
 * @throws {TRPCError} FORBIDDEN if user doesn't have access or doesn't have required role
 */
export async function verifyOrgMembership(params: {
  clerkOrgId: string;
  userId: string;
  requireAdmin?: boolean;
}): Promise<{
  role: string;
  organization: {
    id: string;
    name: string;
    slug: string | null;
    imageUrl: string;
  };
}> {
  // User-centric lookup: get user's orgs (cached)
  const userMemberships = await getCachedUserOrgMemberships(params.userId);

  // Find membership in target org
  const userMembership = userMemberships.find(
    (m) => m.organizationId === params.clerkOrgId
  );

  if (!userMembership) {
    throw new TRPCError({
      code: "FORBIDDEN",
      message: "Access denied to this organization",
    });
  }

  // Check admin requirement if specified
  if (params.requireAdmin && userMembership.role !== "org:admin") {
    throw new TRPCError({
      code: "FORBIDDEN",
      message: "Only administrators can perform this action",
    });
  }

  return {
    role: userMembership.role,
    organization: {
      id: userMembership.organizationId,
      name: userMembership.organizationName,
      slug: userMembership.organizationSlug,
      imageUrl: userMembership.imageUrl,
    },
  };
}

import { db } from "@db/app/client";
import { orgApiKeys } from "@db/app/schema";
import { generateOrgApiKey, hashApiKey } from "@repo/app-api-key";
import {
  createOrgApiKeySchema,
  deleteOrgApiKeySchema,
  revokeOrgApiKeySchema,
  rotateOrgApiKeySchema,
} from "@repo/app-validation/schemas";
import type { TRPCRouterRecord } from "@trpc/server";
import { TRPCError } from "@trpc/server";
import { log } from "@vendor/observability/log/next";
import { and, desc, eq } from "drizzle-orm";
import { orgScopedProcedure } from "../../trpc";

/**
 * Organization API Keys Router
 *
 * Manages org-scoped API keys for secure API access.
 * Each key authenticates the org and can access all resources within it.
 *
 * Security:
 * - Keys are hashed using SHA-256 before storage (never store plaintext)
 * - Full key is only returned once on creation (never again)
 * - Keys can be revoked (soft delete) or permanently deleted
 * - Key rotation atomically revokes old key and creates new one
 */
export const orgApiKeysRouter = {
  /**
   * List all API keys for the org
   * Returns keys with preview only (never full key)
   */
  list: orgScopedProcedure.query(async ({ ctx }) => {
    const keys = await db
      .select({
        publicId: orgApiKeys.publicId,
        name: orgApiKeys.name,
        keyPrefix: orgApiKeys.keyPrefix,
        keySuffix: orgApiKeys.keySuffix,
        isActive: orgApiKeys.isActive,
        expiresAt: orgApiKeys.expiresAt,
        lastUsedAt: orgApiKeys.lastUsedAt,
        createdAt: orgApiKeys.createdAt,
        createdByUserId: orgApiKeys.createdByUserId,
      })
      .from(orgApiKeys)
      .where(eq(orgApiKeys.clerkOrgId, ctx.auth.orgId))
      .orderBy(desc(orgApiKeys.createdAt));

    return keys.map((key) => ({
      id: key.publicId,
      name: key.name,
      keyPreview: `${key.keyPrefix}...${key.keySuffix}`,
      isActive: key.isActive,
      expiresAt: key.expiresAt,
      lastUsedAt: key.lastUsedAt,
      createdAt: key.createdAt,
      createdByUserId: key.createdByUserId,
    }));
  }),

  /**
   * Create a new organization API key
   * Returns the full key ONLY on creation (never again)
   */
  create: orgScopedProcedure
    .input(createOrgApiKeySchema)
    .mutation(async ({ ctx, input }) => {
      const { key, prefix, suffix } = generateOrgApiKey();
      const keyHash = hashApiKey(key);

      const [created] = await db
        .insert(orgApiKeys)
        .values({
          clerkOrgId: ctx.auth.orgId,
          createdByUserId: ctx.auth.userId,
          name: input.name,
          keyHash,
          keyPrefix: prefix,
          keySuffix: suffix,
          expiresAt: input.expiresAt?.toISOString(),
        })
        .returning({
          id: orgApiKeys.id,
          publicId: orgApiKeys.publicId,
        });

      if (!created) {
        log.error("[org-api-keys] create failed", {
          clerkOrgId: ctx.auth.orgId,
          name: input.name,
        });
        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Failed to create API key",
        });
      }

      log.info("[org-api-keys] created", {
        clerkOrgId: ctx.auth.orgId,
        keyId: created.publicId,
        name: input.name,
      });

      return {
        id: created.publicId,
        key, // Full key - only returned once!
        name: input.name,
        keyPreview: `${prefix}...${suffix}`,
        expiresAt: input.expiresAt?.toISOString() ?? null,
        createdAt: new Date().toISOString(),
      };
    }),

  /**
   * Revoke (soft delete) an API key
   * Key remains in database but becomes inactive
   */
  revoke: orgScopedProcedure
    .input(revokeOrgApiKeySchema)
    .mutation(async ({ ctx, input }) => {
      const [existingKey] = await db
        .select({
          id: orgApiKeys.id,
          isActive: orgApiKeys.isActive,
        })
        .from(orgApiKeys)
        .where(
          and(
            eq(orgApiKeys.publicId, input.keyId),
            eq(orgApiKeys.clerkOrgId, ctx.auth.orgId)
          )
        )
        .limit(1);

      if (!existingKey) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "API key not found",
        });
      }

      if (!existingKey.isActive) {
        throw new TRPCError({
          code: "BAD_REQUEST",
          message: "API key is already revoked",
        });
      }

      await db
        .update(orgApiKeys)
        .set({ isActive: false, updatedAt: new Date().toISOString() })
        .where(eq(orgApiKeys.id, existingKey.id));

      log.info("[org-api-keys] revoked", {
        clerkOrgId: ctx.auth.orgId,
        keyId: input.keyId,
      });

      return { success: true };
    }),

  /**
   * Permanently delete an API key
   * Key is removed from database entirely
   */
  delete: orgScopedProcedure
    .input(deleteOrgApiKeySchema)
    .mutation(async ({ ctx, input }) => {
      const [existingKey] = await db
        .select({ id: orgApiKeys.id })
        .from(orgApiKeys)
        .where(
          and(
            eq(orgApiKeys.publicId, input.keyId),
            eq(orgApiKeys.clerkOrgId, ctx.auth.orgId)
          )
        )
        .limit(1);

      if (!existingKey) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "API key not found",
        });
      }

      await db.delete(orgApiKeys).where(eq(orgApiKeys.id, existingKey.id));

      log.info("[org-api-keys] deleted", {
        clerkOrgId: ctx.auth.orgId,
        keyId: input.keyId,
      });

      return { success: true };
    }),

  /**
   * Rotate an API key (revoke old, create new with same name)
   * Returns the new full key ONLY on rotation (never again)
   */
  rotate: orgScopedProcedure
    .input(rotateOrgApiKeySchema)
    .mutation(async ({ ctx, input }) => {
      const [existingKey] = await db
        .select({
          id: orgApiKeys.id,
          name: orgApiKeys.name,
          isActive: orgApiKeys.isActive,
        })
        .from(orgApiKeys)
        .where(
          and(
            eq(orgApiKeys.publicId, input.keyId),
            eq(orgApiKeys.clerkOrgId, ctx.auth.orgId)
          )
        )
        .limit(1);

      if (!existingKey) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "API key not found",
        });
      }

      const { key, prefix, suffix } = generateOrgApiKey();
      const keyHash = hashApiKey(key);

      // Batch: revoke old, create new (atomic — neon-http doesn't support transactions)
      const [, insertResult] = await db.batch([
        // Revoke old key
        db
          .update(orgApiKeys)
          .set({ isActive: false, updatedAt: new Date().toISOString() })
          .where(eq(orgApiKeys.id, existingKey.id)),
        // Create new key
        db
          .insert(orgApiKeys)
          .values({
            clerkOrgId: ctx.auth.orgId,
            createdByUserId: ctx.auth.userId,
            name: existingKey.name,
            keyHash,
            keyPrefix: prefix,
            keySuffix: suffix,
            expiresAt: input.expiresAt?.toISOString(),
          })
          .returning({
            id: orgApiKeys.id,
            publicId: orgApiKeys.publicId,
          }),
      ] as const);

      const [newKey] = insertResult;

      if (!newKey) {
        log.error("[org-api-keys] rotate failed", {
          clerkOrgId: ctx.auth.orgId,
          oldKeyId: input.keyId,
        });
        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Failed to rotate API key",
        });
      }

      log.info("[org-api-keys] rotated", {
        clerkOrgId: ctx.auth.orgId,
        oldKeyId: input.keyId,
        newKeyId: newKey.publicId,
      });

      return {
        id: newKey.publicId,
        key, // Full key - only returned once!
        name: existingKey.name,
        keyPreview: `${prefix}...${suffix}`,
        expiresAt: input.expiresAt?.toISOString() ?? null,
        createdAt: new Date().toISOString(),
      };
    }),
} satisfies TRPCRouterRecord;

